{"path": "/tmp/sv-339caa9b21f341e5a6c6da3e2b402040/Components/Pages/Chat/MessageInput.razor", "file_text": "<div class="message-input">
    <textarea @bind="_text" @bind:event="oninput" placeholder="@Placeholder"
              @onkeydown="HandleKeyDown" rows="2"></textarea>
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string _text = "";

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(_text)) return;
        var msg = _text.Trim();
        _text = "";
        await OnSend.InvokeAsync(msg);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }
}
"}

{"path": "/tmp/sv-339caa9b21f341e5a6c6da3e2b402040/Components/Pages/Chat/MessageBubble.razor", "file_text": "<div class="message-bubble" @onmouseenter="() => _showActions = true"
     @onmouseleave="() => _showActions = false">
    <div class="message-header">
        <strong class="message-author">@Message.Author</strong>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" />

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="HandleReply">
            💬 @ThreadSummary.ReplyCount replies
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="HandleReply" title="Reply in thread">💬 Reply</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀 React</button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleReaction" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<int> OnReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private async Task HandleReply() => await OnReply.InvokeAsync(Message.Id);

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleReaction(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            _ => $"{(int)diff.TotalDays}d ago"
        };
    }
}
"}

