@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        <h2># @Channel.Name</h2>
        <p class="channel-desc">@Channel.Description</p>
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (_isLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var message in Messages)
        {
            var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == message.Id);
            <MessageBubble Message="message"
                           ThreadSummary="summary"
                           OnReply="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                  ButtonLabel="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private bool _isLoadingMore;

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", 
            $"document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 1 && !_isLoadingMore)
        {
            _isLoadingMore = true;
            await OnLoadMore.InvokeAsync();
            _isLoadingMore = false;
        }
    }
}

