arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    SelectedChannelId="_selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    @if (_selectedChannel is not null)
    {
        <MessageArea Channel="_selectedChannel"
                     Messages="_messages"
                     ThreadSummaries="_threadSummaries"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="AddReaction"
                     OnLoadMore="LoadMoreMessages" />
    }
    else
    {
        <div class="message-area empty-state">
            <p>Select a channel to start chatting</p>
        </div>
    }

    @if (_threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply"
                     OnReact="AddReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private List<Message> _threadReplies = [];
    private Channel? _selectedChannel;
    private int _selectedChannelId;
    private Message? _threadRootMessage;

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        BuildThreadSummaries();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);
        // Refresh channels to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (_selectedChannel is null) return;
        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;
        _threadReplies = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(_selectedChannel.Id, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        BuildThreadSummaries();
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh messages to reflect updated reactions
        if (_selectedChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_selectedChannel.Id, 0, _messages.Count);
        }
        if (_threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies pointing to them
        var replyGroups = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = replyGroups.Select(g => new ThreadSummary(
            g.Key,
            g.Count(),
